mapper.select:
select amd.id, amd.agent_memory_id as agentMemoryId, am.memory_name as memoryName, ad.id as agentId, ad.name as agentName, amd.step_name as stepName, amd.step_type as stepType, case amd.step_type when 1 then '判断' when 2 then '原子命令' when 3 then '循环开始' when 4 then '循环结束' else '' end as stepTypeLabel, amd.exec_content as execContent, amd.return_data_format as returnDataFormat, amd.parent_step_id as parentStepId, parent_step.step_name as parentStepName, amd.next_step_id as nextStepId, next_step.step_name as nextStepName, amd.branch_condition as branchCondition, amd.branch_route as branchRoute, amd.model, amd.create_time as createTime, amd.update_time as updateTime, amd.status, amd.remark from agent_memory_detail amd inner join agent_memory am on am.id = amd.agent_memory_id inner join agent_definition ad on ad.id = am.agent_id left join agent_memory_detail parent_step on parent_step.id = amd.parent_step_id left join agent_memory_detail next_step on next_step.id = amd.next_step_id
and (amd.step_name like concat('%', #{pageRequest.keyword}, '%') or am.memory_name like concat('%', #{pageRequest.keyword}, '%') or ad.name like concat('%', #{pageRequest.keyword}, '%'))
and amd.agent_memory_id = #{pageRequest.agentMemoryId}
and am.memory_name like concat('%', #{pageRequest.memoryName}, '%')
and ad.name like concat('%', #{pageRequest.agentName}, '%')
and amd.step_type = #{pageRequest.stepType}
and amd.status = #{pageRequest.status}
order by amd.update_time desc nulls last, amd.create_time desc nulls last limit #{size} offset #{offset}

select count(1)
from agent_memory_detail amd
inner join agent_memory am on am.id = amd.agent_memory_id
inner join agent_definition ad on ad.id = am.agent_id


        and (amd.step_name like concat('%', #{pageRequest.keyword}, '%') or am.memory_name like concat('%', #{pageRequest.keyword}, '%') or ad.name like concat('%', #{pageRequest.keyword}, '%'))


        and amd.agent_memory_id = #{pageRequest.agentMemoryId}


        and am.memory_name like concat('%', #{pageRequest.memoryName}, '%')


        and ad.name like concat('%', #{pageRequest.agentName}, '%')


        and amd.step_type = #{pageRequest.stepType}


        and amd.status = #{pageRequest.status}
